import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class IndentationRuleBugReproductionTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Test 1 - check violations and formatting`() {
        val code =
            """
            class Foo
            @Bar1 @Bar2
            constructor(
                foo1: Foo1,
                foo2: Foo2,
            ) {
                fun foo() = "foo"
            }
            """.trimIndent()
        val formattedCode =
            """
            class Foo
                @Bar1 @Bar2
                constructor(
                    foo1: Foo1,
                    foo2: Foo2,
                ) {
                fun foo() = "foo"
                }
            """.trimIndent()

        // My expectation:
        // class Foo (0)
        // @Bar (4)
        // constructor (4)
        // foo1 (8)
        // ) (4)
        // { (0) ? No, } is line 8. { is line 6.
        // Line 6 is ) {. 
        // ) is at 4. { is at 4?
        // Body starts.
        // fun foo (4).
        // } (0).

        // Violations:
        // 2 (@Bar): 0 -> 4.
        // 3 (constructor): 0 -> 4.
        // 4 (foo1): 4 -> 8.
        // 5 (foo2): 4 -> 8.
        // 6 ( ) { ): 0 -> 4. (Input has ) { at 0).

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasLintViolations(
                LintViolation(2, 1, "Unexpected indentation (0) (should be 4)"),
                LintViolation(3, 1, "Unexpected indentation (0) (should be 4)"),
                LintViolation(4, 1, "Unexpected indentation (4) (should be 8)"),
                LintViolation(5, 1, "Unexpected indentation (4) (should be 8)"),
                LintViolation(6, 1, "Unexpected indentation (0) (should be 4)"),
            ).isFormattedAs(formattedCode)
    }
}
